+        let (command, command_dir, move_pane_id) = match source {
+            SplitSource::Spawn {
+                command,
+                command_dir,
+            } => (command, command_dir, None),
+            SplitSource::MovePane(move_pane_id) => (None, None, Some(move_pane_id)),
+        };
