+        Ok(())
+    }
+
+    fn detachable(&self) -> bool {
+        true
+    }
+
+    fn detach(&self) -> anyhow::Result<()> {
+        self.perform_detach();
+        Ok(())
+    }
+
+    fn state(&self) -> DomainState {
+        if self.inner.lock().unwrap().is_some() {
+            DomainState::Attached
+        } else {
+            DomainState::Detached
+        }
+    }
