+            client: Arc::clone(client),
+            mouse,
+            remote_pane_id,
+            local_pane_id,
+            remote_tab_id,
+            application_palette: Mutex::new(false),
+            renderable: Mutex::new(render),
+            writer: Mutex::new(writer),
+            configured_palette: Mutex::new(palette.clone()),
