+    /// Returns the bitmap strike sizes in this font
+    pub fn pixel_sizes(&self) -> Vec<u16> {
+        let sizes = unsafe {
+            let rec = &(*self.face);
+            from_raw_parts(rec.available_sizes, rec.num_fixed_sizes as usize)
+        };
+        sizes
+            .iter()
+            .filter_map(|info| {
+                if info.height > 0 {
+                    Some(info.height as u16)
+                } else {
+                    None
+                }
+            })
+            .collect()
+    }
