+        let args = FT_Open_Args {
+            flags: FT_OPEN_STREAM,
+            memory_base: ptr::null(),
+            memory_size: 0,
+            pathname: ptr::null_mut(),
+            stream,
+            driver: ptr::null_mut(),
+            num_params: 0,
+            params: ptr::null_mut(),
