+    ) -> anyhow::Result<Vec<ParsedFont>> {
+        Ok(vec![])
+    }
+
+    fn enumerate_all_fonts(&self) -> anyhow::Result<Vec<ParsedFont>> {
+        Ok(vec![])
+    }
+
+    fn locate_fallback_for_codepoints(
+        &self,
+        _codepoints: &[char],
+    ) -> anyhow::Result<Vec<ParsedFont>> {
+        Ok(vec![])
+    }
+}
