+            }
+        } else {
+            let parsed = ParsedFont::from_locator(&locator)?;
+            font_info.push(parsed);
+        }
+        Ok(())
+    }
+
+    for index in 0..num_faces {
+        if let Err(err) = load_one(&lib, &source, index, font_info, &origin) {
+            log::trace!("error while parsing {:?} index {}: {}", source, index, err);
+        }
+    }
