+struct ReduceAnchorsIn {
+    x0: f64,
+    y0: f64,
+    x1: f64,
+    y1: f64,
+    x2: f64,
+    y2: f64,
+}
+
+struct ReduceAnchorsOut {
+    xx0: f64,
+    yy0: f64,
+    xx1: f64,
+    yy1: f64,
+}
+
+fn reduce_anchors(
+    ReduceAnchorsIn {
+        x0,
+        y0,
+        x1,
+        y1,
+        x2,
+        y2,
