+    let q2x = x2 - x0;
+    let q2y = y2 - y0;
+    let q1x = x1 - x0;
+    let q1y = y1 - y0;
+
+    let s = q2x * q2x + q2y * q2y;
+    if s < 0.000001 {
+        return ReduceAnchorsOut {
+            xx0: x0,
+            yy0: y0,
+            xx1: x1,
+            yy1: y1,
+        };
+    }
+
+    let k = (q2x * q1x + q2y * q1y) / s;
+    ReduceAnchorsOut {
+        xx0: x0,
+        yy0: y0,
+        xx1: x1 - k * q2x,
+        yy1: y1 - k * q2y,
