+                    (y + (2. / 3.) * (control_y - y)).into(),
+                    (to_x + (2. / 3.) * (control_x - to_x)).into(),
+                    (to_y + (2. / 3.) * (control_y - to_y)).into(),
+                    (*to_x).into(),
+                    (*to_y).into(),
