+                current.replace((to_x, to_y));
+            }
+            DrawOp::CubicTo {
+                control1_x,
+                control1_y,
+                control2_x,
+                control2_y,
+                to_x,
+                to_y,
+            } => {
+                context.curve_to(
+                    (*control1_x).into(),
+                    (*control1_y).into(),
+                    (*control2_x).into(),
+                    (*control2_y).into(),
+                    (*to_x).into(),
+                    (*to_y).into(),
+                );
+                current.replace((to_x, to_y));
+            }
+            DrawOp::ClosePath => {
+                context.close_path();
+            }
+        }
+    }
