+            // tint this with the actual color in the correct context
+            (0xff, 0xff, 0xff, 1.0)
+        } else {
+            let color = self.face.get_palette_entry(c.palette_index as _)?;
+            (
+                color.red,
+                color.green,
+                color.blue,
+                color.alpha as f64 / 255.,
+            )
+        };
