+        Ok(ColorLine {
+            extend: match line.extend {
+                FT_PaintExtend::FT_COLR_PAINT_EXTEND_PAD => Extend::Pad,
+                FT_PaintExtend::FT_COLR_PAINT_EXTEND_REPEAT => Extend::Repeat,
+                FT_PaintExtend::FT_COLR_PAINT_EXTEND_REFLECT => Extend::Reflect,
