+            rect.origin,
+            Point::new(rect.origin.x, bottom_right.y),
+            color,
+        );
+        self.draw_line(
+            Point::new(bottom_right.x, rect.origin.y),
+            bottom_right,
+            color,
+        );
+        // And the horizontals for the top and bottom
+        self.draw_line(
+            rect.origin,
+            Point::new(bottom_right.x, rect.origin.y),
+            color,
+        );
+        self.draw_line(
