+pub struct ImageTexture {
+    pub image: RefCell<Image>,
+}
+
+impl ImageTexture {
+    pub fn new(width: usize, height: usize) -> Self {
+        let im = Image::new(width, height);
+        Self {
+            image: RefCell::new(im),
